UPDATE employee_info
id_card = #{idCard}, name = #{name}, gender = #{gender}, birth_date = #{birthDate}, phone = #{phone}, email = #{email}, address = #{address}, hire_date = #{hireDate}, status = #{status}, education_level = #{educationLevel}, emergency_contact = #{emergencyContact}, updated_at = CURRENT_TIMESTAMP
WHERE employee_id = #{employeeId}

UPDATE employee_info
SET status = 'deleted', updated_at = CURRENT_TIMESTAMP
WHERE employee_id = #{employeeId}

mapper.select:
SELECT e.employee_id, e.id_card, e.name, e.gender, e.birth_date, e.phone, e.email, e.address, e.hire_date, e.status, e.education_level, e.emergency_contact, e.created_at, e.updated_at, d.dept_name AS primary_dept_name, p.position_name AS primary_position_name FROM employee_info e LEFT JOIN assignment_info a ON e.employee_id = a.employee_id AND a.is_primary = true AND a.status = 'active' LEFT JOIN department_info d ON a.dept_id = d.dept_id LEFT JOIN position_info p ON a.position_id = p.position_id
e.status != 'deleted'
AND e.name LIKE CONCAT('%', #{name}, '%')
AND a.dept_id = #{deptId}
AND a.position_id = #{positionId}
AND e.status = #{status}
ORDER BY e.employee_id ASC
LIMIT #{pageSize} OFFSET #{pageNum}

SELECT COUNT(DISTINCT e.employee_id)
FROM employee_info e
LEFT JOIN assignment_info a ON e.employee_id = a.employee_id AND a.is_primary = true AND a.status = 'active'

    e.status != 'deleted'

        AND e.name LIKE CONCAT('%', #{name}, '%')


        AND a.dept_id = #{deptId}


        AND a.position_id = #{positionId}


        AND e.status = #{status}
